function esc(s){return String(s??'').replace(/[&<>]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;'}[m]))}
function by(arr,id){return arr.find(x=>x.id===id)||arr[0]}function isRealPath(p){return realPaths.includes(p)}function isStylizedWorld(w){return stylizedWorlds.includes(w)}function isRealWorld(w){return realWorlds.includes(w)}function active(){return {path:by(DATA.paths,S.productionPath),project:by(DATA.projects,S.project),world:by(DATA.worlds,S.world),ref:by(DATA.refs,S.reference),palette:by(DATA.palettes,S.palette)}}
function hash32(str){let h=2166136261>>>0;for(let i=0;i<str.length;i++){h^=str.charCodeAt(i);h=Math.imul(h,16777619)}return (h>>>0).toString(16).padStart(8,'0')}
function estimateSec(t){let w=(String(t).match(/\S+/g)||[]).length;return Math.max(3,Math.round((w/2.35+1.5)*10)/10)}function cleanId(i){return 'text#'+String(i+1).padStart(4,'0')}
function defaultScenes(){return [mkScene('Açılış sahnesi: fikri tek güçlü görsel olayla kur.',0),mkScene('Gelişme sahnesi: ana fikrin nasıl çalıştığını göster.',1),mkScene('Final sahnesi: fikir veya marka net kapanışla oturur.',2)]}
function mkScene(source,i,start=0,end=null){let sec=estimateSec(source);return {id:cleanId(i),function:i===0?'Opening Hook':'Build / Proof',vo:source,source,sourceStart:start,sourceEnd:end??start+source.length,sourceHash:hash32(source),sourceLen:source.length,estimatedSec:sec,clipPlan:planClip(sec),visual:'One clear event or reveal.',wi:'Medium',tr:'No Text',ms:sec>13.5?'Show':'Standard',dur:String(Math.min(15,Math.ceil(sec))),character:'Auto',tags:'',logo:'',risk:riskDefault()}}
function planClip(sec){if(sec<=5.5)return '5.5s generate · clean use ~4s · tail 1.5s';if(sec<=7.5)return '7.5s generate · clean use ~6s · tail 1.5s';if(sec<=9.5)return '9.5s generate · clean use ~8s · tail 1.5s';if(sec<=11.5)return '11.5s generate · clean use ~10s · tail 1.5s';return '15s generate · split/multi-shot if meaning exceeds 13.5s · tail 1.5s'}
function defaultState(){let p=by(DATA.projects,'education');return {route:'dashboard',briefRaw:'',client:'',brand:'',objective:'',audience:'',format:'Video',duration:'45-60s',platform:'',project:p.id,productionPath:p.path,world:p.world,reference:p.ref,palette:p.palette,chars:p.chars,scenes:defaultScenes(),rawVault:'',rawHash:'',ingestReport:null,splitMode:'auto',adapt15:true,hybridMode:false,agent:'idea',qaInput:'',repairType:'AI video gibi',refMix:[p.ref],lastDecode:''}}
let memoryState=null;let quotaWarned=false;function storageGet(k){try{return window.localStorage?localStorage.getItem(k):memoryState}catch(e){return memoryState}}function storageSet(k,v){try{if(window.localStorage){localStorage.setItem(k,v);return true}memoryState=v;return true}catch(e){memoryState=v;return false}}function storageRemove(k){try{if(window.localStorage)localStorage.removeItem(k)}catch(e){}memoryState=null}let S;try{S=JSON.parse(storageGet(KEY)||'null')||defaultState()}catch(e){S=defaultState()}function save(){if(!storageSet(KEY,JSON.stringify(S))&&!quotaWarned){quotaWarned=true;try{toast('⚠ Kayıt sınırı doldu: değişiklikler bu oturumda tutuluyor — kapatmadan dışa aktarın')}catch(e){}}}function resetAll(){storageRemove(KEY);S=defaultState();render()}function toast(t){let d=document.createElement('div');d.className='toast';d.textContent=t;document.body.appendChild(d);setTimeout(()=>d.remove(),1500)}function toggleRight(){let p=document.querySelector('.right');if(p)p.classList.toggle('open')}
function recommendedWorldForPath(path){return by(DATA.paths,path).defaultWorld||'clay'}function conflict(){if(S.hybridMode)return null;if(isRealPath(S.productionPath)&&isStylizedWorld(S.world))return {msg:'REAL PATH + STYLIZED WORLD conflict',rec:recommendedWorldForPath(S.productionPath)};if(!isRealPath(S.productionPath)&&isRealWorld(S.world))return {msg:'STYLIZED PATH + REAL WORLD conflict',rec:recommendedWorldForPath(S.productionPath)};return null}function resolveConflict(){let c=conflict();if(c)S.world=c.rec}
function setRoute(r){S.route=r;save();render()}function setProject(id){let p=by(DATA.projects,id);S.project=p.id;S.productionPath=p.path;S.world=p.world;S.reference=p.ref;S.palette=p.palette;S.chars=p.chars||'';S.refMix=[p.ref];resolveConflict();save();render()}function setPath(id){let p=by(DATA.paths,id);S.productionPath=id;let proj=DATA.projects.find(x=>x.path===id);if(proj){S.project=proj.id;S.reference=proj.ref;S.palette=proj.palette;S.chars=proj.chars||'';S.refMix=[proj.ref]}S.world=p.defaultWorld;resolveConflict();save();render()}function setWorld(id){S.world=id;resolveConflict();save();render()}function setRef(id){S.reference=id;S.refMix=[id];save();render()}function setPalette(id){S.palette=id;save();render()}function setField(k,v){S[k]=v;save()}function sw(cs){return '<div class="sw">'+cs.map(c=>`<b style="background:${c}"></b>`).join('')+'</div>'}function pill(t,c=''){return `<span class="pill ${c}">${esc(t)}</span>`}function header(e,t,d){return `<div class="pageHead"><div class="eyebrow">${e}</div><div class="title">${t}</div><div class="desc">${d}</div></div>`}function card(sel,body,click){return `<button class="card ${sel?'sel':''}" onclick="${click}">${body}</button>`}
function grouped(arr,key){return arr.reduce((a,x)=>((a[x[key]]??=[]).push(x),a),{})}function progress(){return Math.round(quantumScore())}
function splitExact(raw,mode){let ranges=[];function push(a,b){if(b>a)ranges.push([a,b])};if(!raw)return [];let m=mode==='auto'?'labels':mode;if(m==='labels'||mode==='auto'){let starts=[...raw.matchAll(/\[text#\d+\]/g)].map(x=>x.index);if(starts.length){if(starts[0]>0)push(0,starts[0]);for(let i=0;i<starts.length;i++)push(starts[i],starts[i+1]??raw.length);return ranges}if(mode==='labels')return [[0,raw.length]]}if(m==='speaker'||mode==='auto'){let starts=[...raw.matchAll(/(^|\n)\s*(DEFNE|ARAS|VO|NARRATOR|ANLATICI|KIZ|ERKEK)\s*:/gi)].map(x=>x.index+(x[1]?1:0));if(starts.length>1){if(starts[0]>0)push(0,starts[0]);for(let i=0;i<starts.length;i++)push(starts[i],starts[i+1]??raw.length);return ranges}if(mode==='speaker')return [[0,raw.length]]}if(m==='paragraph'||mode==='auto'){let last=0;for(const mt of raw.matchAll(/\n\s*\n+/g)){push(last,mt.index+mt[0].length);last=mt.index+mt[0].length}push(last,raw.length);if(ranges.length>1||mode==='paragraph')return ranges}if(m==='line'){let last=0;for(const mt of raw.matchAll(/\n/g)){push(last,mt.index+1);last=mt.index+1}push(last,raw.length);return ranges}return [[0,raw.length]]}
function sentenceRanges(chunk,base,maxSec=13.5){if(estimateSec(chunk)<=maxSec)return [[base,base+chunk.length]];let parts=[],last=0;let re=/[^.!?。！？\n]+[.!?。！？\n]+|[^.!?。！？\n]+$/g;let matches=[...chunk.matchAll(re)];let curStart=0,cur='';for(const mt of matches){let seg=mt[0];if(cur && estimateSec(cur+seg)>maxSec){parts.push([base+curStart,base+mt.index]);curStart=mt.index;cur=seg}else cur+=seg}if(cur)parts.push([base+curStart,base+chunk.length]);return parts.length?parts:[[base,base+chunk.length]]}
function splitRaw(raw,mode,adapt15,maxSec=13.5){let base=splitExact(raw,mode||'auto');let ranges=[];for(const [a,b] of base){let segs=adapt15?sentenceRanges(raw.slice(a,b),a,maxSec):[[a,b]];for(let [s,e] of segs){s=Math.max(0,Math.min(s,raw.length));e=Math.max(s,Math.min(e,raw.length));ranges.push([s,e])}}return ranges}
function ingestRaw(){let raw=S.briefRaw||'';S.rawVault=raw;S.rawHash=hash32(raw);let ranges=splitRaw(raw,S.splitMode||'auto',S.adapt15);S.scenes=ranges.map(([a,b],i)=>mkScene(raw.slice(a,b),i,a,b));let recon=S.scenes.map(s=>s.source).join('');S.ingestReport={rawChars:raw.length,sceneChars:recon.length,rawHash:hash32(raw),reconHash:hash32(recon),coverage:raw===recon?100:Math.round(recon.length/Math.max(1,raw.length)*100),segments:S.scenes.length,mode:S.splitMode,adapt15:S.adapt15};save();toast('Lossless ingest complete');render()}
function sourceIntegrity(){let recon=S.scenes.map(s=>s.source??s.vo??'').join('');let raw=S.rawVault||recon;return {rawChars:raw.length,sceneChars:recon.length,rawHash:hash32(raw),reconHash:hash32(recon),coverage:raw===recon?100:Math.round(recon.length/Math.max(1,raw.length)*100),ok:raw===recon}}
const DECODE_RULES=[{kw:['aras','defne','3. sınıf','eğitim','ders','öğrenci','matematik','sıvı','ölçme'],path:'ANIMATION_EDU',project:'education',reason:'education/Aras-Defne keywords'},{kw:['arcane','spider','anime','stylized','stilize','çizgi','manga'],path:'STYLIZED_PREMIUM',project:'stylized_premium',reason:'stylized keywords'},{kw:['ürün','product','kılıf','telefon','paket','ambalaj','logo','e-ticaret'],path:'PRODUCT_HERO',project:'product_hero',reason:'product/packaging keywords'},{kw:['belediye','kurum','kamu','vatandaş','başkan','23 nisan','bayram','etkinlik'],path:'LIVE_ACTION_CORPORATE',project:s=>['23 nisan','bayram','etkinlik'].some(w=>s.includes(w))?'event_real':'municipality_real',reason:'civic/public keywords'},{kw:['röportaj','testimonial','kurucu','hasta','doktor','müşteri yorumu','insanlı'],path:'HUMAN_TESTIMONIAL',project:'human_testimonial',reason:'human testimonial keywords'},{kw:['belgesel','documentary','gerçek mekan','doğal ışık'],path:'DOCUMENTARY_REALISM',project:'documentary_realism',reason:'documentary keywords'},{kw:['moda','fashion','editorial','tekstil','kumaş','koleksiyon'],path:'FASHION_EDITORIAL',project:'fashion_editorial',reason:'fashion keywords'},{kw:['yemek','food','içecek','kahve','tatlı','sos','burger','makro'],path:'FOOD_MACRO',project:'food_macro',reason:'food macro keywords'},{kw:['otel','mekan','ofis','villa','gayrimenkul','architecture','mimari'],path:'ARCHITECTURE_REAL_ESTATE',project:'architecture_venue',reason:'architecture keywords'},{kw:['medikal','medical','cihaz','saas','app','klinik','teknoloji'],path:'TECH_MEDICAL_PRECISION',project:'tech_medical',reason:'tech/medical keywords'},{kw:['reels','tiktok','instagram','sosyal medya','vertical'],path:'SOCIAL_REELS_REALISM',project:'social_reels',reason:'social/vertical keywords'},{kw:['araba','otomobil','araç','mobility'],path:'AUTOMOTIVE_MOBILITY',project:'automotive_mobility',reason:'automotive keywords'}];
function decodeBrief(raw){let s=(raw||'').toLowerCase();let path='ULTRAREAL_COMMERCIAL',project='ultra_real_commercial';let reason=[];for(const r of DECODE_RULES){if(r.kw.some(w=>s.includes(w))){path=r.path;project=typeof r.project==='function'?r.project(s):r.project;reason.push(r.reason)}}return {path,project:by(DATA.projects,project),reason:reason.join(', ')||'general commercial default'}}
function applyDecoder(){let d=decodeBrief(S.briefRaw);let p=d.project;S.project=p.id;S.productionPath=d.path;S.world=p.world;S.reference=p.ref;S.palette=p.palette;S.chars=p.chars||'';S.refMix=[p.ref];S.lastDecode=d.reason;resolveConflict();if(S.briefRaw)ingestRaw();save();toast('Decoder applied');render()}
function rhythmApply(){let pattern=['Opening Hook','Rule Reveal','Proof Beat','Scale / Detail','Emotional Turn','Brand / Client Role','Resolution / Signature'];S.scenes=S.scenes.map((s,i)=>Object.assign(s,{function:pattern[Math.min(i,pattern.length-1)],visual:s.visual&&s.visual.length>30?s.visual:(isRealPath(S.productionPath)?'A real-film beat that proves the concept through lens, surface, human/product/place behavior.':'A tactile world-explains beat with one dominant object and one motion hook.'),risk:s.risk||riskDefault(),estimatedSec:estimateSec(s.vo||s.source||''),clipPlan:planClip(estimateSec(s.vo||s.source||''))}));save();toast('Shot rhythm applied');render()}
function riskDefault(path){const p=path||((typeof S!=='undefined'&&S&&S.productionPath)?S.productionPath:'ANIMATION_EDU');return isRealPath(p)?'Avoid CGI sheen, stock acting, unstable logo/text, product/face drift.':'Avoid flat slide, random glow, lip movement, material drift.'}
function addScene(){let n=S.scenes.length;S.scenes.push(mkScene('Yeni sahne VO / fikir.',n));save();render()}function delScene(i){S.scenes.splice(i,1);renumberScenes(false);save();render()}function dupScene(i){let c=JSON.parse(JSON.stringify(S.scenes[i]));S.scenes.splice(i+1,0,c);renumberScenes(false);save();render()}function renumberScenes(r=true){S.scenes.forEach((s,i)=>s.id=cleanId(i));save();if(r)render()}function importScenesPrompt(){S.route='ingest';save();render()}
function sceneLines(){return S.scenes.map(s=>`[${s.id}]\nFunction: ${s.function}\nVO / Scene Text: ${s.vo}\nSource Lock: chars ${s.sourceStart??'-'}-${s.sourceEnd??'-'} · len ${s.sourceLen??(s.source||'').length} · hash ${s.sourceHash||hash32(s.source||s.vo||'')}\nVisual Beat: ${s.visual}\nWorld Intensity: ${s.wi}\nText Risk: ${s.tr}\nMotion Safety: ${s.ms}\nEstimated Duration: ~${s.estimatedSec||estimateSec(s.vo)}s\nKling 3.0 Clip Plan: ${s.clipPlan||planClip(estimateSec(s.vo))}\nCharacter Mode: ${s.character}\nAsset Tags: ${s.tags||'-'}\nLogo/Text Note: ${s.logo||'-'}\nProduction Path Note: ${active().path.name}\nRisk Note: ${s.risk||'-'}`).join('\n\n')}
function textPolicy(){return `No Text: no visible text.\nPhysical Text Only: embedded into material/real surface only.\nShort On-Screen Text: max 4 words, stable and readable.\nText Allowed: brief-driven only.\nLogo rule: @logo stable, readable, not stretched, not duplicated.\nNo new text unless requested.`}
function proofFailLines(){return `- Scene source integrity below 100% coverage = FAIL.\n- Real/commercial path + Pixar/clay/diorama/toy-world required look = FAIL.\n- Product path + no geometry/logo/packaging/reflection = FAIL.\n- Human path + no skin/wardrobe/eyeline continuity = FAIL.\n- Documentary/corporate path + magical/toy-world/stock corporate = FAIL.\n- Animation education + no tactile metaphor/motion hook/lip safety = FAIL.\n- Scene IDs skipped/merged/reordered = FAIL.\n- @tags renamed/replaced/reinterpreted = FAIL.\n- Text/logo morph risk unresolved = FAIL.\n- Motion without explicit stable final frame or tail hold = FAIL.`}
function buildBrief(mode='full'){let a=active(), real=isRealPath(S.productionPath), integ=sourceIntegrity();let refs=(S.refMix||[S.reference]).map(id=>by(DATA.refs,id).name).join(' + ');return `MAMILAS PRODUCTION BRIEF\n\nCINEMATIC IDENTITY\nThis is not a prompt sheet. This is the production constitution for a path-aware AI video pipeline.\n\nACTIVE SETUP\nProject: ${a.project.name}\nClient / Brand: ${S.client||'-'}\nBrand / Product: ${S.brand||'-'}\nObjective: ${S.objective||'-'}\nAudience: ${S.audience||'-'}\nFormat: ${S.format||'Video'}\nDuration: ${S.duration||'-'}\nPlatform: ${S.platform||'-'}\nProduction Path: ${a.path.name} / ${S.productionPath}\nRealism / Stylization Level: ${real?'PHOTOREAL / LIVE ACTION / COMMERCIAL':'STYLIZED / ANIMATION / EDUCATION'}\nTone: ${a.project.tone}\nImage Engine: Nano Banana 2 / Gemini Image\nMotion Engine: Kling 3.0\nMusic Engine: Suno v5.5\n\nSOURCE INTEGRITY LAW\nRaw Source Characters: ${integ.rawChars}\nScene Source Characters: ${integ.sceneChars}\nRaw Hash: ${integ.rawHash}\nScene Hash: ${integ.reconHash}\nCoverage: ${integ.coverage}%\nRule: every submitted character must remain traceable through scene source locks. If coverage is below 100%, Proof must FAIL before production.\n\nPATH LOCK\nRequired Look: ${a.path.required}\nForbidden Look: ${a.path.forbidden}\nStylized Override / Hybrid Mode: ${S.hybridMode?'HYBRID OVERRIDE ACTIVE — stylized treatment intentionally selected.':'OFF'}\nPath Conflict Rule: Production Path is supreme. If a downstream prompt contradicts this path, Proof must FAIL it.\n\nWORLD / ENVIRONMENT\nWorld: ${a.world.name}\nWorld Formula: ${a.world.formula}\nRender Lock: ${a.world.render}\nMotion Behavior: ${a.world.motion}\nBest For: ${a.world.best}\nAvoid: ${a.world.avoid}\n\nREFERENCE DNA\nReference Mix: ${refs}\nPrimary Reference Category: ${a.ref.cat}\nUse: camera/light/staging/texture/rhythm/composition grammar only.\nAvoid: ${a.ref.avoid}\nDNA: ${a.ref.dna}\nTranslation: ${a.ref.use}\n\nPALETTE AS LIGHT PHYSICS\nPalette: ${a.palette.name}\nC0 Key Light: ${a.palette.c0}\nC1 Fill/Bounce: ${a.palette.c1}\nC2 Shadow/Depth: ${a.palette.c2}\nC3 Accent/Material Response: ${a.palette.c3}\nLighting Note: palette is light/material behavior, not decoration.\n\nCHARACTER / TAG POLICY\n${S.chars||'No fixed character lock unless user supplies @tag references.'}\n@aras / @defne / @logo / @mekan / @style / @kız / @erkek / custom @tag: visual authorities. Never rename, replace, redesign, or reinterpret tagged assets.\n\nTEXT / LOGO POLICY\n${textPolicy()}\n\nPATH-SPECIFIC QUALITY GATE\n${a.path.gate.map(x=>'- '+x).join('\n')}\n\nIMAGE PHASE CONSTITUTION\nImage agent reads Production Path before World.\n${real?'Real path: photoreal/live-action/commercial start frames with camera/lens, practical/studio light, real material/surface, product/human fidelity, location authenticity, brand role. No Pixar/clay/diorama language.':'Animation/stylized path: tactile metaphor, dominant lesson-object, world-explains, character/lip safety, IP-safe style grammar, one clear motion hook.'}\nEach image prompt must preserve scene source intent, @tags, text/logo state, and motion hook.\n\nMOTION PHASE CONSTITUTION\nKling 3.0: image-to-video, start/end frame compatible, element reference aware, 15s support, flexible duration, multi-shot only when needed, explicit stable final frame.\n${real?'Real path: restrained filmic camera, dolly, rack focus, handheld micro-drift, parallax, product reflection pass, natural human action, edit-friendly hold.':'Animation path: world physics, material response, object life, controlled reveal, safe character movement.'}\nEvery motion prompt must finish main action before final 1.5s tail hold.\n\nSOUND / MUSIC CONSTITUTION\n${real?'Suno v5.5: restrained documentary/commercial score, narration-safe, Custom Mode style layers, no vocals unless requested.':'Suno v5.5: warm educational motif or stylized cinematic bed, narration-safe, Custom Mode style layers, no vocals unless requested.'}\n\nSCENE INTELLIGENCE MATRIX\n${sceneLines()}\n\nPROOFCHECK FAIL CONDITIONS\n${proofFailLines()}\n\nREVISION VOCABULARY\nAI video gibi = physical causality + motivated camera + stable final.\nplastik = material/skin/product surface failure.\ngerçek film gibi = lens/light/surface/context missing.\nreklam gibi = product/brand desire + surface fidelity.\nçok safe = stronger camera/scale/composition, not more random objects.\naynı olmuş = change archetype/lens/movement/transition.\nshow yap = controlled spectacle through camera/light/material.\nmorphing oldu = reduce moving elements and add exact negative.\nyazı bozuldu = freeze text/logo; move only light/camera.\ndrone gibi uçmuyor = add parallax, foreground pass, orbit, low tracking, not zoom.\n`}
function agentPacket(id){let a=active();let base=`MAMILAS ${id.toUpperCase()} DIRECTOR v21\nProduction Path is supreme: ${a.path.name} / ${S.productionPath}.\nScene Source Integrity is law: every [text#] carries source hash, char range, and 15s adaptation.\nPreserve scene IDs, @tags, identity, logo, text, output order, and path lock.\nForbidden Look: ${a.path.forbidden}.\nQuality Gate: ${a.path.gate.join(', ')}.\n`;let map={idea:'You are the creative strategy brain. Decode weak client briefs, choose Production Path before scenario, produce 3 routes, recommend one, write scene architecture and MAMILAS handoff. Reject generic agency ideas.',master:'You are the final brief architect. Build a strict path-aware Final Brief with Source Integrity, Render Lock, Path Lock, World, Reference DNA, Palette Physics, Tags, Scene Matrix, Image/Motion rules and Proof fail lines.',image:'You are the image director. Read Production Path before World. Copy Render Lock verbatim. Real path = photoreal/commercial/live-action frames. Animation path = tactile metaphor and motion-ready start frame. Output one block per [text#].',motion:'You are the Kling 3.0 motion director. Pure motion only. 15s/flexible duration aware. Real path = restrained filmic motion. Animation = material/world physics. Camera first 5 words. Finish main action before tail. Explicit stable final frame.',proof:'You are the strict QA gate. Return PASS/FIX/FAIL. Fail source loss, path contamination, skipped IDs, @tag replacement, weak render lock, text/logo morph risk, no stable final frame, generic AI-video smell.',suno:'You are the music director. Create narration-safe Suno v5.5 Custom Mode style direction by Production Path. Use modular style layers, no vocals unless requested, VO-safe mix.',client:'You are the client pitch wrapper. Convert the brief into sellable client-facing concept rationale, route summary, scene overview and approval text without exposing prompt mechanics.'};return base+'\n'+(map[id]||'Path-aware production agent.')+'\n\nFINAL BRIEF CONTEXT\n'+buildBrief()}
function fallbackCopy(txt){let t=document.createElement('textarea');t.value=txt;t.setAttribute('readonly','');t.style.position='fixed';t.style.left='-9999px';document.body.appendChild(t);t.select();try{document.execCommand('copy');toast('Copied')}catch(e){toast('Copy manually')}document.body.removeChild(t)}function copy(txt){try{if(navigator.clipboard&&window.isSecureContext){navigator.clipboard.writeText(txt).then(()=>toast('Copied')).catch(()=>fallbackCopy(txt))}else fallbackCopy(txt)}catch(e){fallbackCopy(txt)}}function download(name,txt,type='text/plain'){try{let a=document.createElement('a');let url=URL.createObjectURL(new Blob([txt],{type}));a.href=url;a.download=name;document.body.appendChild(a);a.click();setTimeout(()=>{URL.revokeObjectURL(url);a.remove()},500);toast('Export ready')}catch(e){copy(txt)}}
function qaScore(txt){txt=(txt||'');let score=55,notes=[];let lower=txt.toLowerCase();if(lower.includes('production path')||lower.includes('render lock'))score+=8;else notes.push('No Production Path / Render Lock signal.');if(/35mm|50mm|85mm|100mm|macro|lens|dolly|rack focus|handheld|orbit|tracking/i.test(txt))score+=8;else notes.push('Lens/camera language weak.');if(/practical light|studio light|key light|fill|rim|shadow|window light/i.test(txt))score+=8;else notes.push('Lighting not concrete.');if(/surface|texture|skin|fabric|geometry|reflection|material|condensation|viscosity/i.test(txt))score+=8;else notes.push('Material/surface fidelity weak.');if(/final frame|stable|hold|settle|tail/i.test(txt))score+=6;else notes.push('No stable final frame / tail hold.');if(isRealPath(S.productionPath)&&/pixar|clay|diorama|cartoon|toy-world/i.test(txt)){score-=20;notes.push('Real path contamination: stylized/Pixar language detected.')}if(/dynamic|cinematic|beautiful|engaging|vibrant/g.test(lower)){score-=5;notes.push('Empty adjectives detected.')}score=Math.max(0,Math.min(100,score));return {score,notes}}
function repairText(){let t=S.repairType||'AI video gibi';let real=isRealPath(S.productionPath);let fixes={'AI video gibi':'Replace generic zoom/glow with physical cause-effect, motivated camera, material response, and explicit stable final frame.','plastik':'Add matte/real material texture, natural skin/product surface fidelity, remove glossy CGI sheen.','gerçek değil':'Add lens, practical/studio light, authentic location/surface, human/product physics.','reklam gibi değil':'Add brand role, desire, product geometry/surface, reflection, clean negative space.','çok safe':'Increase camera path and scale/composition; do not add random objects.','aynı olmuş':'Change archetype, lens, camera direction, transition and motion beat; preserve identity.','morphing oldu':'Reduce moving elements to one; freeze text/logo/product/face; add exact negatives.','yazı bozuldu':'Freeze text/logo; allow only camera/light/reflection movement.','drone gibi uçmuyor':'Use parallax travel, foreground pass, orbit, low tracking, or object POV; not digital zoom.','source kaybı':'Return to Scene Ingest, use raw vault, verify coverage 100%, then regenerate scene IDs.'};return `REPAIR PATCH — ${t}\nPath: ${active().path.name}\nFix: ${fixes[t]||fixes['AI video gibi']}\nMode: ${real?'real/commercial filmic repair':'animation/stylized tactile repair'}\nCopy into agent: Revise the current output using this repair while preserving scene IDs, source lock, @tags, identity, logo/text, approved still, and Production Path.`}
function qSceneScore(s){let score=40;if((s.function||'').length>4)score+=8;if((s.visual||'').length>25)score+=12;if((s.risk||'').length>12)score+=8;if((s.vo||'').length>20)score+=8;if((s.sourceHash||'').length)score+=12;if((s.clipPlan||'').includes('15s')||estimateSec(s.vo)<=13.5)score+=7;if((s.tags||s.logo||s.character||'').length>3)score+=5;return Math.min(100,score)}function quantumMetrics(){let integ=sourceIntegrity();let scenes=S.scenes.map(qSceneScore),avg=scenes.reduce((x,y)=>x+y,0)/Math.max(1,scenes.length);let path=90;if(conflict())path-=30;if(isRealPath(S.productionPath)&&isStylizedWorld(S.world))path-=40;let agent=95;let data=70+(S.client?5:0)+(S.objective?10:0)+(S.audience?5:0)+(S.brand?5:0);let brief=70+(S.scenes.length>=3?8:0)+(avg>80?8:0)+(S.rawVault?7:0);let source=integ.ok?100:Math.max(0,integ.coverage-20);let risk=isRealPath(S.productionPath)?(S.productionPath==='PRODUCT_HERO'&&!S.brand?72:90):88;return [['Path Fidelity',path],['Scene Intelligence',Math.round(avg)],['Source Integrity',source],['Client Data',Math.min(100,data)],['Brief Completeness',brief],['Agent Alignment',agent],['Production Risk Control',risk]]}function quantumScore(){let m=quantumMetrics();return Math.round(m.reduce((a,b)=>a+b[1],0)/m.length)}function quantumReportText(){let integ=sourceIntegrity();return `MAMILAS QUANTUM REPORT\nScore: ${quantumScore()}\nPath: ${active().path.name}\nProject: ${active().project.name}\nWorld: ${active().world.name}\nReference: ${active().ref.name}\nPalette: ${active().palette.name}\nSource Coverage: ${integ.coverage}%\nRaw Hash: ${integ.rawHash}\nScene Hash: ${integ.reconHash}\n\nMetrics:\n${quantumMetrics().map(x=>'- '+x[0]+': '+x[1]).join('\n')}\n\nNext Actions:\n${nextActions().map(x=>'- '+x).join('\n')}`}function nextActions(){let a=[];let integ=sourceIntegrity();if(!integ.ok)a.push('Fix source integrity: coverage must be 100%.');if(conflict())a.push('Resolve path/world conflict or enable hybrid intentionally.');if(!S.objective)a.push('Fill Objective for better brief.');if(!S.audience)a.push('Fill Audience for client-ready output.');if(S.scenes.some(s=>qSceneScore(s)<82))a.push('Run Shot Rhythm or Quantum Autofill for weak scenes.');if(S.productionPath==='PRODUCT_HERO'&&!S.brand)a.push('Enter product/brand name for Product Hero fidelity.');if(a.length===0)a.push('Export Final Brief and run Image/Motion agents.');return a}function quantumAutofill(){S.scenes=S.scenes.map((s,i)=>Object.assign(s,{function:s.function&&s.function!=='Build / Proof'?s.function:['Opening Hook','Rule Reveal','Proof Beat','Scale / Detail','Emotional Turn','Signature'][i]||'Production Beat',visual:s.visual&&s.visual.length>30?s.visual:(isRealPath(S.productionPath)?'A path-specific real-film visual event proving the idea through lens, light, surface, human/product/place behavior.':'A tactile world-explains event with one dominant lesson-object and one clear motion hook.'),risk:s.risk&&s.risk.length>15?s.risk:riskDefault(),estimatedSec:estimateSec(s.vo||s.source||''),clipPlan:planClip(estimateSec(s.vo||s.source||''))}));save();toast('Quantum Autofill applied');render()}
function pageDashboard(){let a=active();return header('MAMILAS','Quantum Studio OS','Kayıpsız scene ingest, 15s Kling adaptasyonu, reference/palette production physics, final brief constitution ve agent command center.')+`<div class="qHero"><div class="qScore">${quantumScore()}</div><h2>Quantum Readiness</h2><p class="desc">Aktif proje: ${a.project.name} · Path: ${a.path.name} · World: ${a.world.name}</p><div class="row"><button class="btn primary" onclick="setRoute('ingest')">Lossless Scene Ingest</button><button class="btn" onclick="setRoute('quantum')">Quantum Panel</button><button class="btn" onclick="setRoute('final')">Final Brief</button></div></div><div class="grid g3">${quantumMetrics().map(m=>`<div class="box"><h3>${m[0]}</h3><div class="metric"><span>score</span><div class="meter"><b style="width:${m[1]}%"></b></div><b>${m[1]}</b></div></div>`).join('')}</div>`}
function pageDecoder(){return header('STEP 01','Client Brief Decoder','Müşteri briefini yapıştır; site path/project/world/ref/palette önerir. Sonra Ingest ile kayıpsız sahneye böler.')+`<div class="fieldGrid g3"><div><label>Client</label><input value="${esc(S.client)}" oninput="setField('client',this.value)"></div><div><label>Brand/Product</label><input value="${esc(S.brand)}" oninput="setField('brand',this.value)"></div><div><label>Platform</label><input value="${esc(S.platform)}" oninput="setField('platform',this.value)"></div><div><label>Objective</label><input value="${esc(S.objective)}" oninput="setField('objective',this.value)"></div><div><label>Audience</label><input value="${esc(S.audience)}" oninput="setField('audience',this.value)"></div><div><label>Duration</label><input value="${esc(S.duration)}" oninput="setField('duration',this.value)"></div></div><div class="box" style="margin-top:12px"><label>Client Brief / Raw VO</label><textarea oninput="S.briefRaw=this.value;save()" placeholder="Her karakter korunur. Buraya müşteri briefi veya VO batch yapıştır.">${esc(S.briefRaw)}</textarea><div class="row" style="margin-top:10px"><button class="btn primary" onclick="applyDecoder()">Decode + Lossless Ingest</button><button class="btn" onclick="S.briefRaw='23 Nisan için belediye adına gerçek film gibi, çocuk merkezli, klişe bayrak-balon montajı olmayan 45 saniyelik video.\\n\\nBir çocuk sabah kaldırımda tebeşirle kısa bir çizgi çizer.\\n\\nŞehir, o çizgiyi gerçek bir yol gibi dinlemeye başlar.\\n\\nFinalde çocukların fikirleri belediye meydanında küçük ama gerçek bir umut hissi bırakır.';applyDecoder()">23 Nisan Test</button><button class="btn" onclick="S.briefRaw='Premium telefon kılıfı için ultrareal ürün reklamı, materyal hissi, logo stabil, macro yüzey ve refleksiyon.\\n\\nKılıf siyah yüzeyde tek başına durur.\\n\\nIşık aramid dokunun üstünden geçer.\\n\\nFinalde telefon elde kılıfsız hissine yakın ama korumalı görünür.';applyDecoder()">Product Test</button></div></div><div class="box"><h3>Last Decode</h3><p class="desc">${esc(S.lastDecode||'Henüz decode yok.')}</p></div>`}
function pageProject(){let g=grouped(DATA.projects,'category');return header('STEP 02','Project','Preset seç; her preset doğru Production Path ve default world’e bağlı.')+Object.keys(g).map(k=>`<div class="groupTitle">${k}</div><div class="grid g3">${g[k].map(p=>card(S.project===p.id,`${pill(p.tag,p.category==='real'?'blue':'gold')}<h3>${p.icon} ${p.name}</h3><p>${p.desc}</p><em>${p.tip}</em>`,`setProject('${p.id}')`)).join('')}</div>`).join('')}
function pagePath(){return header('STEP 03','Production Path','Ana yasa. Path yanlışsa bütün sistem yanlış kokar.')+`<div class="grid g3">${DATA.paths.map(p=>card(S.productionPath===p.id,`${pill(p.group,p.group==='real'?'blue':'gold')}<h3>${p.icon} ${p.name}</h3><p>${p.desc}</p><em>Required: ${p.required}</em>`,`setPath('${p.id}')`)).join('')}</div><div class="box"><h3>Hybrid Override</h3><p class="desc">Bilinçli real+stylized hybrid için açılır. Aksi halde conflict resolver otomatik düzeltir.</p><button class="btn ${S.hybridMode?'primary':'ghost'}" onclick="S.hybridMode=!S.hybridMode;save();render()">${S.hybridMode?'HYBRID ON':'HYBRID OFF'}</button></div>`}
function pageWorld(){let show=S.hybridMode?DATA.worlds:DATA.worlds.filter(w=>isRealPath(S.productionPath)?w.group==='REAL':w.group==='STYLIZED');let g=grouped(show,'group');return header('STEP 04','World / Environment','Real path gerçek ortam/stüdyo; animation path tactile dünya ister.')+(conflict()?`<div class="box" style="border-color:var(--red)"><h3>Conflict</h3><p class="desc">${conflict().msg} → öneri: ${conflict().rec}</p></div>`:'')+Object.keys(g).map(k=>`<div class="groupTitle">${k}</div><div class="grid g3">${g[k].map(w=>card(S.world===w.id,`${pill(w.group,w.group==='REAL'?'blue':'gold')}<h3>${w.name}</h3><p>${w.best}</p>${sw(w.colors)}<em>Avoid: ${w.avoid}</em>`,`setWorld('${w.id}')`)).join('')}</div>`).join('')}


function pageReference(){
 if(!S.refSearch)S.refSearch='';
 if(!S.refCat)S.refCat='ALL';
 if(!S.refFav)S.refFav=[];
 let allCats=['ALL'].concat([...new Set(DATA.refs.map(r=>r.cat))].sort());
 let q=(S.refSearch||'').toLowerCase();
 let list=DATA.refs.filter(r=>(S.refCat==='ALL'||r.cat===S.refCat) && (!q || (r.name+' '+r.cat+' '+r.use+' '+(r.dna||'')+' '+(r.anchor||'')).toLowerCase().includes(q)));
 let g=grouped(list,'cat');
 let active=(S.refMix||[]).map(id=>by(DATA.refs,id).name).join(' + ');
 return header('REFERENCE ENGINE','Reference DNA Mixer','Referanslar anime, animasyon, oyun, reklam, ürün ve live-action DNA olarak çalışır. Preview anchor gösterir; prompt IP-safe grammar üretir.')+
 `<div class="refVaultStats"><div class="refStat"><span>References</span><b>${DATA.refs.length}</b></div><div class="refStat"><span>Shown</span><b>${list.length}</b></div><div class="refStat"><span>Categories</span><b>${allCats.length-1}</b></div><div class="refStat"><span>Favorites</span><b>${S.refFav.length}</b></div></div>`+
 `<div class="refTools"><input placeholder="Search: bleach, luffy, miles, zelda, product..." value="${esc(S.refSearch)}" oninput="S.refSearch=this.value;save();render()"><select onchange="S.refCat=this.value;save();render()">${allCats.map(c=>`<option ${S.refCat===c?'selected':''}>${c}</option>`).join('')}</select><button class="btn" onclick="S.refCat='ALL';S.refSearch='';save();render()">Clear</button></div>`+
 `<div class="box"><h3>Active Mix</h3><p class="desc">${active||'No reference selected'}</p>${(S.refMix||[]).length >= 3 ? '<div style="margin-top:8px;background:#f5c84222;border:1px solid #f5c84280;border-radius:8px;padding:8px 10px;font:11px monospace;color:#f5c842">⚠ 3+ ref seçildi → Primary DNA / Secondary Accent / Forbidden Blend hiyerarşisi ata.</div>' : ''}<div class="row"><button class="btn" onclick="S.refMix=[S.reference];save();render()">Reset Mix</button><button class="btn primary" onclick="copy((S.refMix||[]).map(id=>by(DATA.refs,id).name+' — '+by(DATA.refs,id).dna).join('\\n'))">Copy DNA Mix</button></div><p class="desc" style="margin-top:8px">Kural: preview anchor gösterebilir; prompt karakter/logo/kostüm/shot kopyalamaz.</p></div>`+
 Object.keys(g).map(cat=>`<div class="groupTitle">${cat}</div><div class="grid g3">${g[cat].map(r=>card((S.refMix||[]).includes(r.id),`${pill(r.cat,'purple')} ${S.refFav.includes(r.id)?pill('★ fav','gold'):''}<h3>${r.name}</h3><div class="refCardPreview ${r.preview||'default'}">${r.anchor?`<span class="refAnchor">${r.anchor}</span>`:''}</div><p>${r.dna||r.use}</p><em>Use: ${r.use} · Avoid: ${r.avoid}</em><div class="row" style="margin-top:8px"><span class="pill" onclick="event.stopPropagation(); if(!S.refFav)S.refFav=[]; S.refFav.includes('${r.id}')?S.refFav=S.refFav.filter(x=>x!=='${r.id}'):S.refFav.push('${r.id}'); save();render()">★ Favorite</span></div>`,`S.reference='${r.id}'; if(!S.refMix)S.refMix=[]; if(S.refMix.includes('${r.id}'))S.refMix=S.refMix.filter(x=>x!=='${r.id}'); else S.refMix.push('${r.id}'); if(!S.refMix.length)S.refMix=['${r.id}']; save();render()`)).join('')}</div>`).join('');
}

function pagePalette(){return header('STEP 06','Palette / Light Physics','Palet renk değil; key/fill/shadow/material response sistemidir.')+`<div class="grid g3">${DATA.palettes.map(p=>card(S.palette===p.id,`<h3>${p.name}</h3>${sw(p.colors)}<p><b>C0</b> ${p.c0}<br><b>C1</b> ${p.c1}<br><b>C2</b> ${p.c2}<br><b>C3</b> ${p.c3}</p><em>Use: ${p.use} · Avoid: ${p.avoid}</em>`,`setPalette('${p.id}')`)).join('')}</div>`}
function pageIngest(){let rep=S.ingestReport||sourceIntegrity();return header('STEP 07','Lossless Scene Ingest','Buraya yapıştırılan hiçbir karakter kaybolmaz. Scene source lock, hash, char range ve 15s adaptasyonu üretir.')+`<div class="box"><label>Raw Source Vault</label><textarea oninput="S.briefRaw=this.value;save()" placeholder="Raw VO / script / customer text. No character will be discarded.">${esc(S.briefRaw)}</textarea><div class="fieldGrid g3"><div><label>Split Mode</label><select onchange="S.splitMode=this.value;save();render()"><option value="auto" ${S.splitMode==='auto'?'selected':''}>Auto</option><option value="labels" ${S.splitMode==='labels'?'selected':''}>Existing [text#]</option><option value="paragraph" ${S.splitMode==='paragraph'?'selected':''}>Paragraph</option><option value="speaker" ${S.splitMode==='speaker'?'selected':''}>Speaker</option><option value="line" ${S.splitMode==='line'?'selected':''}>Line</option></select></div><div><label>15s Adapt</label><select onchange="S.adapt15=this.value==='true';save();render()"><option value="true" ${S.adapt15?'selected':''}>ON — split long chunks</option><option value="false" ${!S.adapt15?'selected':''}>OFF — preserve chunks</option></select></div><div><label>Action</label><button class="btn primary" onclick="ingestRaw()">Lossless Ingest</button></div></div></div><div class="grid g3"><div class="box"><h3>Coverage</h3><div class="qScore" style="font-size:42px">${rep.coverage??0}%</div></div><div class="box"><h3>Raw Hash</h3><p class="qaResult">${rep.rawHash||'-'}</p></div><div class="box"><h3>Scene Hash</h3><p class="qaResult">${rep.reconHash||'-'}</p></div></div><div class="qaResult">Segments: ${rep.segments||S.scenes.length}\nRaw Chars: ${rep.rawChars||0}\nScene Chars: ${rep.sceneChars||0}\nMode: ${S.splitMode}\n15s Adapt: ${S.adapt15?'ON':'OFF'}</div>`}
function sceneHTML(s,i){let score=qSceneScore(s);return `<div class="scene ${s.sourceHash?'sourceLocked':''} ${score<82?'warn':''}"><div class="sceneHead"><span class="sid">${esc(s.id)}</span><div class="row">${pill('Q '+score,score>=85?'ok':'gold')}${pill('~'+(s.estimatedSec||estimateSec(s.vo))+'s',(s.estimatedSec||estimateSec(s.vo))<=15?'ok':'bad')}<button class="btn sm" onclick="dupScene(${i})">Dup</button><button class="btn sm danger" onclick="delScene(${i})">Sil</button></div></div><div class="sourceMini">SOURCE LOCK · chars ${s.sourceStart??'-'}-${s.sourceEnd??'-'} · len ${s.sourceLen??(s.source||'').length} · hash ${s.sourceHash||hash32(s.source||s.vo||'')} · ${s.clipPlan||planClip(estimateSec(s.vo))}</div><div class="fieldGrid g3"><div><label>Function</label><input value="${esc(s.function)}" oninput="S.scenes[${i}].function=this.value;save()"></div><div><label>Duration</label><input value="${esc(s.dur)}" oninput="S.scenes[${i}].dur=this.value;save()"></div><div><label>Character</label><input value="${esc(s.character)}" oninput="S.scenes[${i}].character=this.value;save()"></div></div><label>VO / Scene Text</label><textarea oninput="S.scenes[${i}].vo=this.value;S.scenes[${i}].estimatedSec=estimateSec(this.value);S.scenes[${i}].clipPlan=planClip(S.scenes[${i}].estimatedSec);save()">${esc(s.vo)}</textarea><label>Exact Source Segment</label><textarea oninput="S.scenes[${i}].source=this.value;S.scenes[${i}].sourceLen=this.value.length;S.scenes[${i}].sourceHash=hash32(this.value);save()">${esc(s.source??s.vo)}</textarea><label>Visual Beat</label><textarea oninput="S.scenes[${i}].visual=this.value;save()">${esc(s.visual)}</textarea><div class="sceneAdvanced"><select onchange="S.scenes[${i}].wi=this.value;save()"><option ${s.wi==='Full'?'selected':''}>Full</option><option ${s.wi==='Medium'?'selected':''}>Medium</option><option ${s.wi==='Light'?'selected':''}>Light</option><option ${s.wi==='Off'?'selected':''}>Off</option></select><select onchange="S.scenes[${i}].tr=this.value;save()"><option ${s.tr==='No Text'?'selected':''}>No Text</option><option ${s.tr==='Physical Text Only'?'selected':''}>Physical Text Only</option><option ${s.tr==='Short On-Screen Text'?'selected':''}>Short On-Screen Text</option><option ${s.tr==='Text Allowed'?'selected':''}>Text Allowed</option></select><select onchange="S.scenes[${i}].ms=this.value;save()"><option ${s.ms==='Safe'?'selected':''}>Safe</option><option ${s.ms==='Standard'?'selected':''}>Standard</option><option ${s.ms==='Show'?'selected':''}>Show</option><option ${s.ms==='Experimental'?'selected':''}>Experimental</option></select><input placeholder="@tags" value="${esc(s.tags)}" oninput="S.scenes[${i}].tags=this.value;save()"><textarea placeholder="Logo/Text note" oninput="S.scenes[${i}].logo=this.value;save()">${esc(s.logo)}</textarea><textarea placeholder="Risk note" oninput="S.scenes[${i}].risk=this.value;save()">${esc(s.risk)}</textarea></div></div>`}
function pageScenes(){return header('STEP 08','Scene Editor','Önemsiz alan yok. Her sahne source lock, 15s plan, visual beat, risk ve QA taşır.')+`<div class="copyBar"><div class="row"><button class="btn primary" onclick="addScene()">+ Sahne</button><button class="btn" onclick="renumberScenes()">Renumber</button><button class="btn" onclick="importScenesPrompt()">Lossless Import</button><button class="btn" onclick="download('mamilas_scenes.json',JSON.stringify(S.scenes,null,2),'application/json')">JSON</button><button class="btn" onclick="download('mamilas_scenes.csv',csvScenes(),'text/csv')">CSV</button></div></div>${S.scenes.map(sceneHTML).join('')}`}
function csvScenes(){let head=['id','function','vo','source','sourceStart','sourceEnd','sourceHash','visual','wi','tr','ms','dur','estimatedSec','clipPlan','character','tags','logo','risk'];let rows=S.scenes.map(s=>head.map(k=>`"${String(s[k]||'').replace(/"/g,'""')}"`).join(','));return head.join(',')+'\n'+rows.join('\n')}
